# Example PROJECTS_DB that would be available in the actual setup
PROJECTS_DB = {
    'project1': {'name': 'Project One', 'status': 'active'},
    'project2': {'name': 'Project Two', 'status': 'inactive'}
}

def get_project_settings(project_key):
    """
    Retrieves the current settings of a project.

    Args:
        project_key (str): The unique identifier for the project

    Returns:
        dict: The settings dictionary for the specified project
    """
    return PROJECTS_DB.get(project_key, {})

turn2_code:
# Example PROJECTS_DB that would be available in the actual setup
PROJECTS_DB = {
    'project1': {
        'name': 'Project One', 
        'status': 'active',
        'members': {
            'user1': {'role': 'admin'},
            'user2': {'role': 'viewer'},
            'user3': {'role': 'editor'}
        }
    },
    'project2': {
        'name': 'Project Two', 
        'status': 'inactive',
        'members': {
            'user1': {'role': 'viewer'},
            'user4': {'role': 'admin'}
        }
    }
}

# Roles that can view or modify settings
ALLOWED_ROLES = {'admin', 'editor'}

def get_project_settings(project_key):
    """
    Retrieves the current settings of a project.

    Args:
        project_key (str): The unique identifier for the project

    Returns:
        dict: The settings dictionary for the specified project
    """
    return PROJECTS_DB.get(project_key, {})

def check_user_role(member_id, project_key):
    """
    Checks if a user has permission to view or modify project settings.

    Args:
        member_id (str): The unique identifier for the member
        project_key (str): The unique identifier for the project

    Returns:
        bool: True if user is a member with allowed role, False otherwise
    """
    project = PROJECTS_DB.get(project_key, {})
    members = project.get('members', {})

    if member_id in members:
        user_role = members[member_id].get('role', '')
        return user_role in ALLOWED_ROLES

    return False

prompts:
['Create a function named 'edit_project_settings', which gives users the ability to update project settings in a shared project management application. The function's name should be edit_project_settings. The function should take 4 arguments, i.e., - member_id: str, the unique identifier of the user attempting the modification, - role: str, describing the role of the user (e.g., 'project_manager', 'team_member', or 'viewer'), - project_key: str, the identifier of the project whose settings should be changed, - updated_configuration: dict, the updated settings for the project. The function should return Returns a success message upon successfully updating the project settings if the user is authorized, otherwise raises a permissions error. The function should raise - Raises a PermissionError for an unauthorized access. The following setup code will be provided to you:
```
PROJECTS_DB = {
    "PROJ001": {
        "project_id": "PROJ001",
        "creator_id": "USER1",
        "members": ["USER1", "USER2", "USER3"],
        "settings": {"visibility": "private", "deadline": "2023-12-31"}
    },
    "PROJ002": {
        "project_id": "PROJ002",
        "creator_id": "USER4",
        "members": ["USER4", "USER5"],
        "settings": {"visibility": "public", "deadline": "2023-10-15"}
    }
}
```

